Here's a refactored version that eliminates the repetition:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace DuplicateMagic.Tests;

[TestClass]
public class DiscountServiceTests
{
    private DiscountService _service = null!;

    [TestInitialize]
    public void Setup() => _service = new DiscountService();

    [DataTestMethod]
    [DataRow("Gold", 100.0, 90.0)]
    [DataRow("Gold", 200.0, 180.0)]
    [DataRow("Gold", 50.0, 45.0)]
    [DataRow("Silver", 100.0, 95.0)]
    [DataRow("Silver", 200.0, 190.0)]
    [DataRow("Silver", 50.0, 47.5)]
    public void ApplyDiscount_ReturnsExpectedAmount(string tier, double price, double expected)
    {
        var result = _service.ApplyDiscount((decimal)price, tier);
        Assert.AreEqual((decimal)expected, result);
    }

    [DataTestMethod]
    [DataRow(42, 7, 3, 882.0)]
    [DataRow(150, 7, 3, 3150.0)]
    public void CalculateShipping_ReturnsExpectedCost(int weight, int distance, int zone, double expected)
    {
        var result = _service.CalculateShipping(weight, distance, zone);
        Assert.AreEqual((decimal)expected, result);
    }

    [DataTestMethod]
    [DataRow(100.0, 0.08, 108.0)]
    [DataRow(200.0, 0.08, 216.0)]
    [DataRow(100.0, 0.125, 112.5)]
    [DataRow(200.0, 0.125, 225.0)]
    [DataRow(100.0, 0.0, 100.0)]
    public void ApplyTax_ReturnsExpectedTotal(double amount, double rate, double expected)
    {
        var result = _service.ApplyTax((decimal)amount, (decimal)rate);
        Assert.AreEqual((decimal)expected, result);
    }
}
```

**Key improvements:**

1. **`[TestInitialize]`** — creates the service once per test, removing duplication.
2. **`[DataTestMethod]` + `[DataRow]`** — collapses repeated tests into parameterized cases. Each `DataRow` still runs as its own test in the runner, so failures are isolated.
3. **Single tax assertion per row** — the original crammed 5 checks into one test; a failure on line 2 would hide lines 3–5.

> Note: `[DataRow]` doesn't support `decimal` literals directly, so `double` params are cast to `decimal` inside the method. If precision matters for edge cases, consider a custom `[DynamicData]` source instead.
